import { useMemo } from 'react';

/**
 * базовая статусная модель
 */
export type BaseStatuses = 'default' | 'error' | 'warning' | 'success' | 'info';
/**
 * расширяет базовые статусы цветовыми
 */
export type AllStatuses = BaseStatuses | 'purple' | 'magenta' | 'teal';
/**
 * цветовая модель (например для компонента Avatar)
 */
export type ColorTypes = 'grey' | 'red' | 'green' | 'orange' | 'blue' | 'purple' | 'magenta' | 'teal';

/**
 * TODO: удалить когда перестанет использоваться useColorInteadOfStatus
 *
 * переходная вспомогательная сущность,
 * нужна для плавного перехода компонентов,
 * которые раньше подчинялись статусной модели, на цветовую модель
 *
 * мапит название статуса на соответствующий ему цвет
 */
export const STATUS_TO_COLOR_MAP: Map<AllStatuses, ColorTypes> = new Map([
	['default', 'grey'],
	['error', 'red'],
	['warning', 'orange'],
	['success', 'green'],
	['info', 'blue'],
	['purple', 'purple'],
	['magenta', 'magenta'],
	['teal', 'teal'],
]);

/**
 * TODO: удалить когда перестанет использоваться во всех компонентах
 *
 * переходный хук, нужен для обратной совместимости при переходе от использования статусной модели к цветовой
 *
 * Проверяет передан ли type, если да, то выводит в консоль предупреждение и мапит его на цвет в соответствии с {@link STATUS_TO_COLOR_MAP}
 */
export const useColorInteadOfStatus = (
	{ type, color }: { type: AllStatuses; color: ColorTypes },
	componentName: string,
): ColorTypes =>
	useMemo(() => {
		if (type) {
			console.warn(`[${componentName}] props "type" is deprecated, use "color" instead`);
			return color ? color : STATUS_TO_COLOR_MAP.get(type);
		}

		return color || 'grey';
	}, [color, type, componentName]);
